### 為什麼 Zod

```text
// 沒驗證
function createUser(data: any) {
    return prisma.user.create({ data });
    // data 可能是任何垃圾
}

// 用 Zod
import { z } from "zod";

const UserSchema = z.object({
    name: z.string().min(1),
    email: z.string().email(),
    age: z.number().int().positive()
});

function createUser(data: unknown) {
    const validated = UserSchema.parse(data);    // 自動驗證
    // validated 自動有型別！
    return prisma.user.create({ data: validated });
}

// 錯誤
createUser({ name: "", email: "not-email" });
// ZodError: name 不能空、email 格式錯
```


### 基本 schema

```text
import { z } from "zod";

// 原始型別
z.string();
z.number();
z.boolean();
z.date();
z.null();
z.undefined();

// 進階
z.string().min(3).max(20);
z.string().email();
z.string().url();
z.string().uuid();
z.string().regex(/^[a-z]+$/);
z.string().startsWith("https://");

z.number().int();
z.number().positive();
z.number().min(0).max(100);
z.number().multipleOf(5);

z.array(z.string());
z.array(z.number()).min(1).max(10);

z.object({
    name: z.string(),
    age: z.number()
});

// Optional / Nullable
z.string().optional();        // string | undefined
z.string().nullable();         // string | null
z.string().nullish();          // string | null | undefined

// Default
z.string().default("Anonymous");
z.number().default(0);

// 自訂錯誤訊息
