### 進階：Union / Intersection / Literal

```text
// Literal（固定值）
z.literal("admin");
z.literal(42);

// Enum
const Role = z.enum(["admin", "user", "guest"]);
type RoleType = z.infer;
// "admin" | "user" | "guest"

// Native enum
enum Color { Red, Green, Blue }
z.nativeEnum(Color);

// Union（多型別）
z.union([z.string(), z.number()]);
// 簡寫
z.string().or(z.number());

// Discriminated union
const Shape = z.discriminatedUnion("type", [
    z.object({ type: z.literal("circle"), radius: z.number() }),
    z.object({ type: z.literal("square"), side: z.number() })
]);

// Intersection
const A = z.object({ name: z.string() });
const B = z.object({ age: z.number() });
const C = A.and(B);   // { name: string; age: number }

// Tuple
z.tuple([z.string(), z.number(), z.boolean()]);
// [string, number, boolean]

// Record
z.record(z.string(), z.number());
// { [key: string]: number }

// Map / Set
z.map(z.string(), z.number());
z.set(z.string());
```


### 自訂驗證 + transform

```text
// 自訂驗證
const Password = z.string()
    .min(8, "至少 8 字")
    .refine(s => /[A-Z]/.test(s), "需要大寫")
    .refine(s => /[0-9]/.test(s), "需要數字");

// 跨欄位驗證
const RegisterSchema = z.object({
    password: z.string().min(8),
    passwordConfirm: z.string()
}).refine(
    data => data.password === data.passwordConfirm,
    { message: "密碼不一致", path: ["passwordConfirm"] }
);

// Transform（驗證 + 轉換）
const TrimmedString = z.string().trim();
const LowerEmail = z.string().email().toLowerCase();

const NumberFromString = z.string().transform((s) => parseInt(s, 10));

// Parse from query string
const QuerySchema = z.object({
    page: z.string().transform(Number).default("1"),
    limit: z.string().transform(Number).default("10")
});

// Chain
const PriceSchema = z.string()
    .transform(s => parseFloat(s))
    .pipe(z.number().positive());
```


### Parse vs SafeParse

```text
// parse：失敗 throw
try {
    const user = UserSchema.parse(input);
} catch (err) {
    if (err instanceof z.ZodError) {
        console.log(err.errors);
    }
}

// safeParse：回 { success, data | error }
const result = UserSchema.safeParse(input);
if (!result.success) {
    return res.status(400).json({ errors: result.error.errors });
}
const user = result.data;

// Express middleware
function validate(schema: z.Schema) {
    return (req, res, next) => {
        const result = schema.safeParse(req.body);
        if (!result.success) {
            return res.status(400).json({
                errors: result.error.errors
            });
        }
        req.body = result.data;
        next();
    };
}

app.post("/users", validate(UserSchema), (req, res) => {
    // req.body 已驗證 + 有型別
});
```


