### JWT 完整實作

```text
import jwt from "jsonwebtoken";

const JWT_SECRET = process.env.JWT_SECRET!;
const JWT_EXPIRES_IN = "1h";

// 生 token
function createToken(payload: { userId: number }): string {
    return jwt.sign(payload, JWT_SECRET, {
        expiresIn: JWT_EXPIRES_IN
    });
}

// 驗證
function verifyToken(token: string): { userId: number } {
    return jwt.verify(token, JWT_SECRET) as { userId: number };
}

// 登入 endpoint
app.post("/login", async (req, res) => {
    const { email, password } = req.body;

    const user = await prisma.user.findUnique({ where: { email } });
    if (!user) return res.status(401).json({ error: "Invalid" });

    const valid = await bcrypt.compare(password, user.password);
    if (!valid) return res.status(401).json({ error: "Invalid" });

    const token = createToken({ userId: user.id });
    res.json({ token, user: { id: user.id, email: user.email } });
});

// Middleware：驗 token
async function authenticate(req, res, next) {
    const authHeader = req.headers.authorization;
    if (!authHeader?.startsWith("Bearer ")) {
        return res.status(401).json({ error: "No token" });
    }

    const token = authHeader.slice(7);

    try {
        const payload = verifyToken(token);
        const user = await prisma.user.findUnique({
            where: { id: payload.userId }
        });
        if (!user) return res.status(401).json({ error: "User not found" });

        req.user = user;
        next();
    } catch (err) {
        res.status(401).json({ error: "Invalid token" });
    }
}

// 保護的 endpoint
app.get("/me", authenticate, (req, res) => {
    res.json(req.user);
});

app.delete("/posts/:id", authenticate, async (req, res) => {
    const post = await prisma.post.findUnique({
        where: { id: Number(req.params.id) }
    });
    if (post.authorId !== req.user.id) {
        return res.status(403).json({ error: "Forbidden" });
    }
    await prisma.post.delete({ where: { id: post.id } });
    res.status(204).end();
});
```


### Refresh Token Pattern

```text
// Access token 短（15 分鐘）
// Refresh token 長（30 天、存 DB）

const ACCESS_EXPIRES = "15m";
const REFRESH_EXPIRES = "30d";

app.post("/login", async (req, res) => {
    const user = await authenticate(req.body);

    const accessToken = jwt.sign(
        { userId: user.id, type: "access" },
        JWT_SECRET,
        { expiresIn: ACCESS_EXPIRES }
    );

    const refreshToken = jwt.sign(
        { userId: user.id, type: "refresh" },
        JWT_SECRET,
        { expiresIn: REFRESH_EXPIRES }
    );

    // 存 refresh token（能撤銷）
    await prisma.refreshToken.create({
        data: {
            token: refreshToken,
            userId: user.id,
            expiresAt: new Date(Date.now() + 30 * 24 * 3600 * 1000)
        }
    });

    res.json({ accessToken, refreshToken });
});

app.post("/refresh", async (req, res) => {
    const { refreshToken } = req.body;

    try {
        const payload = jwt.verify(refreshToken, JWT_SECRET) as any;
        if (payload.type !== "refresh") throw new Error();
    } catch {
        return res.status(401).json({ error: "Invalid refresh token" });
    }

    // 檢查 DB 沒被撤銷
    const dbToken = await prisma.refreshToken.findUnique({
        where: { token: refreshToken }
    });
    if (!dbToken) return res.status(401).json({ error: "Revoked" });

    // 生新 access token
    const newAccessToken = jwt.sign(
        { userId: payload.userId, type: "access" },
        JWT_SECRET,
        { expiresIn: ACCESS_EXPIRES }
    );

    res.json({ accessToken: newAccessToken });
});

app.post("/logout", authenticate, async (req, res) => {
    const { refreshToken } = req.body;
    await prisma.refreshToken.delete({ where: { token: refreshToken } });
    res.status(204).end();
});
```


### Session-based（cookie）

```text
# 不用 JWT、用 server session（適合單一網站）

