// 2. Worker 處理
new Worker("videos", async (job) => {
    const { videoId, steps } = job.data;

    if (steps.includes("transcode")) {
        await job.updateProgress(0);
        await transcodeVideo(videoId);
        await job.updateProgress(50);
    }

    if (steps.includes("thumbnail")) {
        await generateThumbnail(videoId);
        await job.updateProgress(75);
    }

    if (steps.includes("subtitles")) {
        await generateSubtitles(videoId);
        await job.updateProgress(100);
    }

    await prisma.video.update({
        where: { id: videoId },
        data: { status: "ready" }
    });

    // 通知 user（推播 / email）
    await notificationQueue.add("video-ready", { videoId });
